        '    Sentry.captureException(error, {',
        '      extra: { componentStack: info },',
        '    });',
        '  }',
        '',
        '  render() {',
        '    if (this.state.hasError) {',
        '      return <ErrorFallback',
        '        onRetry={() => this.setState({})}',
